```javascript
/**
 * Encodes a (created_at, id) pair into an opaque, URL-safe base64 cursor.
 *
 * base64url avoids the +, /, and = characters that would require percent-encoding
 * when the cursor appears as a query parameter (e.g. ?after=abc_xyz).
 *
 * @param {Date|string} createdAt - created_at of the last returned row
 * @param {number|string} id      - id of the last returned row
 * @returns {string} URL-safe base64 cursor
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: createdAt instanceof Date ? createdAt.toISOString() : createdAt,
        id,
    });
    // Buffer.from(...).toString('base64url') requires Node.js >= 16.
    // For older Node, replace with:
    //   .toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '')
    return Buffer.from(payload).toString('base64url');
}

/**
 * Decodes a base64url cursor back to { created_at, id }.
 * Returns null on ANY failure — malformed JSON, missing fields, invalid date.
 * The caller is responsible for converting null into a 400 response.
 *
 * @param {string} cursor
 * @returns {{ created_at: string, id: number|string } | null}
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const payload = JSON.parse(json);

        if (payload.created_at === undefined || payload.id === undefined) {
            return null; // structurally invalid
        }
        if (isNaN(new Date(payload.created_at).getTime())) {
            return null; // created_at is not a valid timestamp string
        }

        return { created_at: payload.created_at, id: payload.id };
    } catch {
        return null; // Buffer decode error or JSON.parse failure
    }
}

/**
 * GET /api/posts?limit=20&after=<cursor>
 *
 * Returns a stable, index-efficient page of published posts ordered by
 * (created_at DESC, id DESC).  No OFFSET, no COUNT(*).
 */
async function getPosts(req, res) {
    // Cap limit to prevent abuse; default 20.
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterParam = req.query.after;

    // --- Decode cursor (if provided) -----------------------------------------
    let cursor = null;
    if (afterParam !== undefined) {
        cursor = decodeCursor(afterParam);
        if (!cursor) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or tampered.',
            });
        }
    }

    // --- Build query ---------------------------------------------------------
    //
    // The compound row-value comparison:
    //
    //   (created_at, id) < ($1::timestamptz, $2::int)
    //
    // is semantically identical to:
    //
    //   created_at < $1
    //   OR (created_at = $1 AND id < $2)
    //
    // Because ORDER BY is DESC on both columns, "after the cursor" means
    // "a smaller (created_at, id) pair".  PostgreSQL evaluates this with a
    // single btree index seek on (created_at DESC, id DESC) — O(log n),
    // not O(n) like OFFSET.
    //
    // We fetch limit + 1 rows.  If we get that extra row back, we know there
    // is at least one more page; we discard it before responding.
    //
    let result;

    if (cursor) {
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1::timestamptz, $2::int)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1],
        );
    } else {
        // No cursor supplied → first page; no WHERE filter on position.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1],
        );
    }

    // --- Apply N+1 trick -----------------------------------------------------
    const rows = result.rows;
    const hasMore = rows.length > limit;

    // Discard the sentinel extra row before sending to the client.
    const posts = hasMore ? rows.slice(0, limit) : rows;

    // Build the next cursor from the LAST row we are actually returning,
    // not the sentinel.  If the page is empty or there is no next page,
    // nextCursor stays null.
    let nextCursor = null;
    if (hasMore && posts.length > 0) {
        const last = posts[posts.length - 1];
        nextCursor = encodeCursor(last.created_at, last.id);
    }

    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,  // null when on the last page
            limit,
        },
    });
}
```

---

### Recommended index

To make the cursor WHERE clause and the ORDER BY both use the same index, create:

```sql
CREATE INDEX idx_posts_cursor
    ON posts (created_at DESC, id DESC)
    WHERE published = true;
```

The partial index (`WHERE published = true`) matches the query's filter exactly, keeping it narrow and fast.

---

### Why cursor-based pagination is strictly better here

| Problem | Offset pagination | Cursor pagination |
|---|---|---|
| **Stability under writes** | A new post inserted on page 1 while the user is on page 3 shifts every subsequent page's offset, causing **row skips or duplicates** across page fetches. | The cursor pins to a specific `(created_at, id)` position in the ordered set; concurrent inserts/deletes before that position are invisible. |
| **Performance at depth** | `OFFSET 10000` forces PostgreSQL to **scan and discard 10 000 rows** on every request even if they will never be read. Cost grows linearly with depth. | The row-value comparison `(created_at, id) < ($1, $2)` lets PostgreSQL **seek directly** into the btree index in O(log n), making page 500 just as fast as page 1. |
| **Eliminating `COUNT(*)`** | Requires a full table/index scan on every request to compute `totalPages`. On a 50 M-row table this is hundreds of milliseconds. | Replaced entirely by the N+1 trick — one extra row costs nothing and tells you everything you need to know about whether a next page exists. |
| **Correct semantics** | Page numbers are a fiction that breaks the moment the dataset changes. | Cursors are a true bookmark into the ordered stream, which is what clients actually need for "load more" / infinite scroll UIs. |

The one trade-off is that you lose **random access** (you cannot jump to page 47). If your product genuinely needs that, keep offset pagination for that specific use case; for feeds and infinite-scroll lists, cursors are unambiguously the right tool.

